import{_ as i,o as a,c as t,aA as n}from"./chunks/framework.LoNIaX4s.js";const h=JSON.parse('{"title":"TransmissionLinelist.jl","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),r={name:"index.md"};function o(s,e,l,d,p,u){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="TransmissionLinelist.jl" tabindex="-1">TransmissionLinelist.jl <a class="header-anchor" href="#TransmissionLinelist.jl" aria-label="Permalink to &quot;TransmissionLinelist.jl {#TransmissionLinelist.jl}&quot;">​</a></h1><p>A Julia + Turing model fitted to the Epuyén 2018–19 Andes hantavirus outbreak (<a href="https://doi.org/10.1056/NEJMoa2009040" target="_blank" rel="noreferrer">Martínez et al. 2020, NEJM</a>).</p><p>Four quantities are estimated jointly from the line list: the incubation period, the transmission timing of each secondary infection relative to its source&#39;s symptom onset, a weekly time-varying reproduction number, and offspring dispersion. Exposure and onset dates are interval-censored. Each case is given a continuous latent infection time and a continuous latent onset time, each sampled within its recorded window. Generation interval and serial interval are derived from the fitted distributions in post-processing.</p><h2 id="Pages" tabindex="-1">Pages <a class="header-anchor" href="#Pages" aria-label="Permalink to &quot;Pages {#Pages}&quot;">​</a></h2><ul><li><p><a href="./model">Model</a> — priors, data augmentation, GI / SI derivation.</p></li><li><p><a href="./limitations">Limitations</a> — known caveats around exposure encoding, late R(t) bins, dispersion identifiability, and right-truncation.</p></li><li><p><a href="./analysis">Analysis walkthrough</a> — runs the full analysis end to end.</p></li><li><p><a href="./api">API Reference</a> — exported functions.</p></li></ul><h2 id="Citing" tabindex="-1">Citing <a class="header-anchor" href="#Citing" aria-label="Permalink to &quot;Citing {#Citing}&quot;">​</a></h2><blockquote><p>Martínez VP, Di Paola N, Alonso DO, et al. <em>&quot;Super-spreaders&quot; and person-to-person transmission of Andes virus in Argentina.</em> N Engl J Med 2020;383:2230–41. <a href="https://doi.org/10.1056/NEJMoa2009040" target="_blank" rel="noreferrer">doi:10.1056/NEJMoa2009040</a></p></blockquote><p>The reporting follows:</p><blockquote><p>Charniga K, et al. <em>Best practices for estimating and reporting epidemiological delay distributions of infectious diseases.</em> 2024. <a href="https://arxiv.org/abs/2405.08841" target="_blank" rel="noreferrer">arXiv:2405.08841</a></p></blockquote>',9)])])}const m=i(r,[["render",o]]);export{h as __pageData,m as default};
